import Link from "next/link";
import { redirect } from "next/navigation";
import { Building2, ChevronRight, CirclePlus } from "lucide-react";
import { prisma } from "@/lib/prisma";
import { requireSessionUser } from "@/lib/session";
import styles from "../page.module.css";

function getUserFullName(user: {
  firstName: string | null;
  lastName: string | null;
  name: string | null;
  email: string;
}) {
  return `${user.firstName ?? ""} ${user.lastName ?? ""}`.trim() || user.name || user.email;
}

export default async function CompaniesPage() {
  const { user } = await requireSessionUser();

  if (user.role !== "SUPERADMIN") {
    redirect("/dashboard");
  }

  const companies = await prisma.company.findMany({
    include: {
      users: {
        where: { role: "COMPANY_ADMIN" },
        orderBy: { createdAt: "desc" },
        take: 1,
      },
      _count: {
        select: {
          employees: true,
          devices: true,
        },
      },
    },
    orderBy: { createdAt: "desc" },
  });

  return (
    <div className={styles.page}>
      <section className={`glass-panel ${styles.heroCard}`}>
        <div>
          <p className={styles.eyebrow}>Firmalar</p>
          <h1 className={styles.title}>Musteri Firma Yonetimi</h1>
          <p className={styles.subtitle}>
            Tanimli firmalari listeleyebilir, detaylarina gidip inceleyebilir ve duzenleyebilirsin.
          </p>
        </div>

        <Link href="/dashboard/companies/new" className={styles.primaryLinkButton}>
          <CirclePlus size={18} />
          <span>Yeni Firma Ekle</span>
        </Link>
      </section>

      <section className={styles.cardGridWide}>
        {companies.length === 0 ? (
          <article className={`glass-panel ${styles.sectionCard}`}>
            <p className={styles.emptyState}>Henuz firma tanimi yapilmadi.</p>
          </article>
        ) : (
          companies.map((company) => (
            <Link
              key={company.id}
              href={`/dashboard/companies/${company.id}`}
              className={`glass-panel ${styles.companyCardLink}`}
            >
              <div className={styles.infoCardTop}>
                <div className={styles.companyCardHeader}>
                  <div className={styles.metricIcon}>
                    <Building2 size={18} />
                  </div>
                  <div>
                    <p className={styles.infoCardTitle}>{company.name}</p>
                    <p className={styles.infoCardMeta}>
                      {company.users[0]
                        ? getUserFullName(company.users[0])
                        : "Firma admini tanimlanmadi"}
                    </p>
                  </div>
                </div>
                <ChevronRight size={18} className={styles.chevronIcon} />
              </div>

              <p className={styles.infoCardBody}>
                {company.address ?? "Adres bilgisi henuz girilmedi."}
              </p>

              <div className={styles.infoCardFooter}>
                <span>Iletisim: {company.contactEmail ?? company.contactPhone ?? "-"}</span>
                <span>
                  {company._count.employees} personel / {company._count.devices} cihaz
                </span>
              </div>
            </Link>
          ))
        )}
      </section>
    </div>
  );
}
